from dataclasses import dataclass, asdict
from enum import Enum

class TradeState(Enum):
    PENDING = "pending"
    ACCEPTED = "accepted"
    COMPLETED = "completed"
    CANCELLED = "cancelled"

@dataclass
class Item:
    item_id: str
    name: str
    owner_id: str
    quantity: int
    
    def to_dict(self):
        return asdict(self)

@dataclass
class Player:
    player_id: str
    username: str
    session_token: str
    inventory: Dict[str, Item]
    
class TradeTransaction:
    def __init__(self, trade_id: str, initiator_id: str, recipient_id: str):
        self.trade_id = trade_id
        self.initiator_id = initiator_id
        self.recipient_id = recipient_id
        self.initiator_items: Dict[str, int] = {}
        self.recipient_items: Dict[str, int] = {}
        self.initiator_accepted = False
        self.recipient_accepted = False
        self.state = TradeState.PENDING
        self.lock = asyncio.Lock()
        self.created_at = datetime.utcnow()
        
    def is_expired(self) -> bool:
        return datetime.utcnow() - self.created_at > timedelta(minutes=5)

class GameServer:
    def __init__(self):
        self.players: Dict[str, Player] = {}
        self.connections: Dict[str, websockets.WebSocketServerProtocol] = {}
        self.active_trades: Dict[str, TradeTransaction] = {}
        self.global_lock = asyncio.Lock()
        self.player_locks: Dict[str, asyncio.Lock] = {}
        self.authenticated_sessions: Dict[str, str] = {}
        
    def _get_player_lock(self, player_id: str) -> asyncio.Lock:
        if player_id not in self.player_locks:
            self.player_locks[player_id] = asyncio.Lock()
        return self.player_locks[player_id]
    
    def _generate_session_token(self) -> str:
        return secrets.token_urlsafe(32)
    
    def _hash_password(self, password: str) -> str:
        return hashlib.sha256(password.encode()).hexdigest()
    
    async def authenticate_player(self, username: str, password: str) -> Optional[str]:
        async with self.global_lock:
            player_id = self._hash_password(username)
            
            if player_id not in self.players:
                session_token = self._generate_session_token()
                self.players[player_id] = Player(
                    player_id=player_id,
                    username=username,
                    session_token=session_token,
                    inventory={}
                )
                self._initialize_player_inventory(player_id)
            else:
                session_token = self._generate_session_token()
                self.players[player_id].session_token = session_token
            
            self.authenticated_sessions[session_token] = player_id
            return session_token
    
    def _initialize_player_inventory(self, player_id: str):
        starter_items = [
            Item(str(uuid.uuid4()), "Sword", player_id, 1),
            Item(str(uuid.uuid4()), "Potion", player_id, 5),
            Item(str(uuid.uuid4()), "Gold", player_id, 100)
        ]
        for item in starter_items:
            self.players[player_id].inventory[item.item_id] = item
    
    def _verify_session(self, session_token: str) -> Optional[str]:
        return self.authenticated_sessions.get(session_token)
    
    async def handle_client(self, websocket, path):
        session_token = None
        player_id = None
        
        try:
            async for message in websocket:
                try:
                    data = json.loads(message)
                    
                    if not isinstance(data, dict):
                        await self._send_error(websocket, "Invalid message format")
                        continue
                    
                    action = data.get("action")
                    
                    if action == "authenticate":
                        username = data.get("username", "")
                        password = data.get("password", "")
                        
                        if not username or not password or len(username) > 50:
                            await self._send_error(websocket, "Invalid credentials")
                            continue
                        
                        session_token = await self.authenticate_player(username, password)
                        player_id = self._verify_session(session_token)
                        
                        if player_id:
                            self.connections[player_id] = websocket
                            await self._send_response(websocket, {
                                "action": "authenticated",
                                "session_token": session_token,
                                "player_id": player_id
                            })
                        continue
                    
                    request_token = data.get("session_token")
                    if not request_token:
                        await self._send_error(websocket, "Authentication required")
                        continue
                    
                    verified_player_id = self._verify_session(request_token)
                    if not verified_player_id:
                        await self._send_error(websocket, "Invalid session")
                        continue
                    
                    player_id = verified_player_id
                    
                    if action == "get_inventory":
                        await self._handle_get_inventory(websocket, player_id)
                    elif action == "initiate_trade":
                        await self._handle_initiate_trade(websocket, player_id, data)
                    elif action == "add_trade_items":
                        await self._handle_add_trade_items(websocket, player_id, data)
                    elif action == "accept_trade":
                        await self._handle_accept_trade(websocket, player_id, data)
                    elif action == "cancel_trade":
                        await self._handle_cancel_trade(websocket, player_id, data)
                    else:
                        await self._send_error(websocket, "Unknown action")
                        
                except json.JSONDecodeError:
                    await self._send_error(websocket, "Invalid JSON")
                except Exception as e:
                    await self._send_error(websocket, "Internal error")
                    
        except websockets.exceptions.ConnectionClosed:
            pass
        finally:
            if player_id and player_id in self.connections:
                del self.connections[player_id]
    
    async def _send_response(self, websocket, data):
        await websocket.send(json.dumps(data))
    
    async def _send_error(self, websocket, error_message):
        await websocket.send(json.dumps({"error": error_message}))
    
    async def _handle_get_inventory(self, websocket, player_id: str):
        async with self._get_player_lock(player_id):
            player = self.players.get(player_id)
            if not player:
                await self._send_error(websocket, "Player not found")
                return
            
            inventory_list = [item.to_dict() for item in player.inventory.values()]
            await self._send_response(websocket, {
                "action": "inventory",
                "items": inventory_list
            })
    
    async def _handle_initiate_trade(self, websocket, player_id: str, data: dict):
        recipient_id = data.get("recipient_id")
        
        if not recipient_id or not isinstance(recipient_id, str):
            await self._send_error(websocket, "Invalid recipient")
            return
        
        if recipient_id == player_id:
            await self._send_error(websocket, "Cannot trade with yourself")
            return
        
        if recipient_id not in self.players:
            await self._send_error(websocket, "Recipient not found")
            return
        
        trade_id = str(uuid.uuid4())
        trade = TradeTransaction(trade_id, player_id, recipient_id)
        
        async with self.global_lock:
            self.active_trades[trade_id] = trade
        
        await self._send_response(websocket, {
            "action": "trade_initiated",
            "trade_id": trade_id
        })
        
        if recipient_id in self.connections:
            await self._send_response(self.connections[recipient_id], {
                "action": "trade_request",
                "trade_id": trade_id,
                "from_player": player_id
            })
    
    async def _handle_add_trade_items(self, websocket, player_id: str, data: dict):
        trade_id = data.get("trade_id")
